definition.script:
pipeline {
    agent any
    triggers {
        pollSCM('H/5 * * * *')
    }
    environment {
        APP_NAME  = 'dotnet-app'
        REGISTRY  = 'localhost:5000/arcana'
        IMAGE_TAG = "${REGISTRY}/${APP_NAME}"
        VERSION   = '0.2.0'
    }
    options {
        timeout(time: 15, unit: 'MINUTES')
        disableConcurrentBuilds()
        buildDiscarder(logRotator(numToKeepStr: '10'))
    }
    stages {
        stage('Checkout') {
            steps {
                dir("${env.PROJECTS_DIR}/arcana-windows") {
                    git url: 'https://github.com/jrjohn/arcana-windows.git',
                        branch: 'main', credentialsId: 'github-credentials'
                }
            }
        }
        stage('Docker Build') {
            steps {
                dir("${env.PROJECTS_DIR}/arcana-windows") {
                    sh "VERSION=${VERSION} docker compose build"
                    sh "docker tag ${IMAGE_TAG}:${VERSION} ${IMAGE_TAG}:build-${BUILD_NUMBER}"
                }
            }
        }
        stage('Unit Tests') {
            steps {
                dir("${env.PROJECTS_DIR}/arcana-windows") {
                    catchError(buildResult: 'SUCCESS', stageResult: 'UNSTABLE') {
                        sh "docker compose -f docker-compose.test.yml run --rm --build test"
                    }
                }
            }
        }
        stage('SonarQube Analysis') {
            steps {
                dir("${env.PROJECTS_DIR}/arcana-windows") {
                    catchError(buildResult: 'SUCCESS', stageResult: 'UNSTABLE') {
                        sh """SONAR_TOKEN=squ_5ce2319b9d8ca2b1db4e0f5bdf36b34249561f18 SONAR_HOST_URL=http://sonarqube:9000/sonarqube SONAR_PROJECT_KEY=dotnet-app SONAR_PROJECT_NAME='Dotnet App' docker compose -f docker-compose.sonar.yml run --rm --build sonar"""
                    }
                }
            }
        }
        stage('Image Info') {
            steps {
                sh "docker images --format 'table {{.Repository}}:{{.Tag}}	{{.Size}}' ${IMAGE_TAG}:${VERSION}"
            }
        }
        stage('Push to Registry') {
            steps {
                sh "docker push ${IMAGE_TAG}:${VERSION}"
                sh "docker push ${IMAGE_TAG}:build-${BUILD_NUMBER}"
            }
        }
    }
    post {
        success { echo "Pipeline SUCCESS - arcana-windows .NET ${APP_NAME}:${VERSION}" }
        failure { echo "Pipeline FAILED" }
        always  { echo "Build number ${BUILD_NUMBER} done" }
    }
}
